// Load CRON-TEST job configuration
const JOB_NAME = 'cron-test';

const fs = require('fs');
const path = `/data/jobs/${JOB_NAME}.json`;

try {
  const configData = fs.readFileSync(path, 'utf8');
  const config = JSON.parse(configData);

  // Return one item per source
  const items = config.sources.map(source => ({
    json: {
      config: config,
      source: source,
      jobName: JOB_NAME
    }
  }));

  return items;
} catch (error) {
  throw new Error(`Could not read job config at ${path}: ${error.message}`);
}

// rssFeedRead splits the feed into individual items - each item IS one article.
// config was on the pre-RSS items; pull it back from the Load Config node.
const config = $('Load Config').first().json.config;
const now = new Date();
const lookbackHours = config?.lookback_hours || 24;
const maxAgeMs = lookbackHours * 60 * 60 * 1000;

const allArticles = [];
for (const item of $input.all()) {
  const pubDate = new Date(item.json.pubDate || item.json.isoDate || Date.now());
  if ((now - pubDate) <= maxAgeMs) {
    allArticles.push({
      json: {
        title: item.json.title || 'Untitled',
        description: item.json.contentSnippet || item.json.content || item.json.summary || '',
        link: item.json.link || item.json.guid || '',
        pubDate: pubDate.toISOString(),
        source: item.json.feedTitle || 'News'
      }
    });
  }
}

const maxArticles = config?.max_articles || 60;
return allArticles.slice(0, maxArticles);

const config = $('Load Config').first().json.config;
const items = $input.all();
if (items.length === 0 || !items[0].json.articles || items[0].json.articles.length === 0) {
  throw new Error('No articles reached Build Prompt - check Filter Articles output');
}

// Aggregate stores items as plain objects, NOT wrapped in .json
const articles = items[0].json.articles;
let articleList = '';
for (const article of articles) {
  articleList += `\n- **${article.title}** (${article.source}): ${(article.description || '').substring(0, 200)}`;
}

const systemPrompt = config.system_prompt || 'You are a news summarizer.';
const userPrompt = (config.user_prompt_format || 'Summarize these news articles:') + articleList;

return [{
  json: {
    config,
    articleCount: articles.length,
    // Pre-build the Ollama request body to avoid n8n expression serialisation issues
    ollamaBody: JSON.stringify({
      model: config.model,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user',   content: userPrompt }
      ],
      stream: false,
      options: config.ollama_options || {}
    })
  }
}];

const config = $('Load Config').first().json.config;
const httpResponse = $input.first().json;

const summary = httpResponse?.message?.content
  || (typeof httpResponse?.message === 'string' ? httpResponse.message : null)
  || httpResponse?.response
  || 'No summary returned.';

const today = new Date().toISOString().split('T')[0];

let webhookUrl = config?.discord?.webhook_url || '';
const envVar = config?.discord?.webhook_url_env;
if (!webhookUrl && envVar && $env[envVar]) webhookUrl = $env[envVar];
if (!webhookUrl) throw new Error(`No Discord webhook URL. Set ${envVar || 'DISCORD_WEBHOOK_URL'} in .env or discord.webhook_url in the job config.`);

// Split into <=4000-char chunks (Discord embed limit)
const MAX = 4000;
const chunks = [];
if (summary.length <= MAX) {
  chunks.push(summary);
} else {
  const parts = summary.split('\n\n');
  let current = '';
  for (const part of parts) {
    if ((current + part).length > MAX) {
      if (current) chunks.push(current.trim());
      current = part;
    } else {
      current += (current ? '\n\n' : '') + part;
    }
  }
  if (current) chunks.push(current.trim());
}

const title = config?.name || 'News Digest';
const embeds = chunks.map((chunk, i) => ({
  title: i === 0 ? `${title} - ${today}` : `${title} (cont.)`,
  description: chunk,
  color: config?.discord?.embed_color || 3447003,
  footer: { text: i === chunks.length - 1
    ? `Generated by ${config?.model || 'Ollama'}`
    : `Part ${i + 1}/${chunks.length}` }
}));

const discordBody = JSON.stringify({ username: config?.discord?.username || 'News Bot', embeds });
return [{ json: { webhookUrl, discordBody } }];

// Log that we're skipping Discord
const items = $input.all();
const item = items[0]?.json;

if (item?.skipDiscord) {
  console.log('Skipping Discord:', item.reason);
  return [{
    json: {
      message: 'Discord sending skipped',
      reason: item.reason,
      summary: item.summary
    }
  }];
}

return [];
